---
import type { HTMLAttributes } from "astro/types"

import "@/styles/global.css"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"html">

const { class: className, lang, ...props } = Astro.props
---

<html
  class={cn(
    "bg-background text-foreground has-data-[variant=inset]:bg-sidebar overscroll-none scroll-smooth",
    className
  )}
  data-slot="layout"
  lang={Astro.currentLocale || "en"}
  {...props}
>
  <slot />
</html>

<style is:global>
  :root {
    --container: 1280px;
    color-scheme: light;
  }

  .dark {
    color-scheme: dark;
  }

  @view-transition {
    navigation: auto;
  }
</style>

---
import { AstroSeo } from "@lexingtonthemes/seo"
import type { ImageMetadata } from "astro"
import { Font, getImage } from "astro:assets"

type Props = {
  name?: string
  title?: string
  description?: string
  image?: {
    src?: ImageMetadata | string
    alt?: string
  }
  noindex?: boolean
  nofollow?: boolean
  canonical?: string
}

const baseUrl = Astro.site?.origin || Astro.url.origin
const pagePathname = Astro.url.pathname.endsWith("/")
  ? Astro.url.pathname
  : `${Astro.url.pathname}/`

const {
  name,
  title,
  description,
  image,
  noindex,
  nofollow,
  canonical,
  ...props
} = Astro.props

const resolvedCanonical = new URL(canonical || pagePathname, baseUrl).toString()

const toImageMimeType = (format?: string) => {
  if (!format) return undefined
  if (format.includes("/")) return format
  if (format === "jpg") return "image/jpeg"
  return `image/${format}`
}

const transformedImage =
  image?.src && typeof image.src !== "string"
    ? await getImage({
        src: image.src,
        format: "png",
        width: 1200,
        height: 630,
        quality: "medium",
      })
    : undefined

const openGraphImage =
  typeof image?.src === "string"
    ? {
        url: new URL(image.src, baseUrl).toString(),
        alt: image.alt,
      }
    : transformedImage
      ? {
          url: new URL(transformedImage.src, baseUrl).toString(),
          alt: image?.alt,
          width: transformedImage.attributes.width,
          height: transformedImage.attributes.height,
          type: toImageMimeType(transformedImage.attributes.format),
        }
      : undefined
---

<head data-slot="layout-head" {...props}>
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <meta name="generator" content={Astro.generator} />
  <meta charset="utf-8" />
  <Font cssVariable="--font-sans" />
  <Font cssVariable="--font-mono" />
  <AstroSeo
    title={title}
    description={description}
    canonical={resolvedCanonical}
    noindex={noindex}
    nofollow={nofollow}
    openGraph={{
      url: resolvedCanonical,
      type: "website",
      ...(name && { site_name: name }),
      ...(openGraphImage && {
        images: [
          {
            ...openGraphImage,
            ...(openGraphImage.url.startsWith("https://") && {
              secureUrl: openGraphImage.url,
            }),
          },
        ],
      }),
    }}
  />
  <slot />
</head>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"body">

const { class: className, ...props } = Astro.props
---

<body
  class={cn(
    "bg-background text-foreground overscroll-none antialiased",
    className
  )}
  data-slot="layout-body"
  {...props}
>
  <slot />
</body>

<style is:global>
  body {
    font-family: var(--font-sans);
  }
</style>
